import React from "react";
import { CreditCard, ArrowDownLeft, ArrowUpRight } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function HomeScreen({ balance, savingsBalance, transactions = [], userName, openScreen }) {
  return (
    <div className="px-6 pb-24 bg-gradient-to-b from-teal-50 to-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Hello, {userName} 👋</h1>

      {/* Balance Cards */}
      <div className="space-y-4 mb-6">
        <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 flex justify-between items-center">
          <div>
            <p className="text-gray-500 text-sm">Main Balance</p>
            <p className="text-2xl font-bold text-teal-600">${formatCurrency(balance)}</p>
          </div>
          <button
            onClick={() => openScreen("Deposit")}
            className="px-4 py-2 bg-teal-600 text-white rounded-xl hover:bg-teal-700 transition-colors"
          >
            Deposit
          </button>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 flex justify-between items-center">
          <div>
            <p className="text-gray-500 text-sm">Savings Balance</p>
            <p className="text-2xl font-bold text-emerald-600">${formatCurrency(savingsBalance)}</p>
          </div>
          <button
            onClick={() => openScreen("SavingsDeposit")}
            className="px-4 py-2 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-colors"
          >
            Save
          </button>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="flex gap-4 mb-6">
        <button
          onClick={() => openScreen("Withdraw")}
          className="flex-1 flex items-center justify-center gap-2 p-4 bg-white rounded-xl shadow-md hover:bg-gray-100 transition-colors"
        >
          <ArrowUpRight className="w-5 h-5 text-red-600" /> Withdraw
        </button>
        <button
          onClick={() => openScreen("SavingsWithdraw")}
          className="flex-1 flex items-center justify-center gap-2 p-4 bg-white rounded-xl shadow-md hover:bg-gray-100 transition-colors"
        >
          <CreditCard className="w-5 h-5 text-emerald-600" /> Withdraw Savings
        </button>
      </div>

      {/* Recent Transactions */}
      <h2 className="text-xl font-semibold mb-3">Recent Transactions</h2>
      {transactions.length === 0 ? (
        <p className="text-gray-500">No transactions yet.</p>
      ) : (
        <div className="space-y-3">
          {transactions.slice(0, 5).map((t) => (
            <div
              key={t.id}
              className="flex items-center justify-between bg-white p-4 rounded-xl shadow-sm border border-gray-100 cursor-pointer hover:bg-gray-50"
              onClick={() => openScreen("TransactionReceipt")}
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center ${
                    t.type.includes("deposit") ? "bg-emerald-100 text-emerald-600" : "bg-red-100 text-red-600"
                  }`}
                >
                  {t.type.includes("deposit") ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                </div>
                <div>
                  <p className="font-semibold text-gray-800">{t.title}</p>
                  <p className="text-xs text-gray-400">{t.date}</p>
                </div>
              </div>
              <span
                className={`font-bold text-sm ${
                  t.type.includes("deposit") ? "text-emerald-600" : "text-gray-800"
                }`}
              >
                {t.type.includes("deposit") ? "+" : "-"}${formatCurrency(t.amount)}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
